import{_ as e,o as t,c as i,a2 as s}from"./chunks/framework.DCVnL8g5.js";const u=JSON.parse('{"title":"Rendimiento cache y rate limiting","description":"","frontmatter":{},"headers":[],"relativePath":"full-stack/arquitectura/apis-rest/11-rendimiento-cache-y-rate-limiting.md","filePath":"full-stack/arquitectura/apis-rest/11-rendimiento-cache-y-rate-limiting.md","lastUpdated":1782521464000}'),n={name:"full-stack/arquitectura/apis-rest/11-rendimiento-cache-y-rate-limiting.md"};function o(l,a,p,c,r,d){return t(),i("div",null,[...a[0]||(a[0]=[s(`<h1 id="rendimiento-cache-y-rate-limiting" tabindex="-1">Rendimiento cache y rate limiting <a class="header-anchor" href="#rendimiento-cache-y-rate-limiting" aria-label="Permalink to &quot;Rendimiento cache y rate limiting&quot;">​</a></h1><p>El rendimiento de una API no depende solo del codigo. Tambien depende del contrato, la paginacion, la cache y los limites.</p><h2 id="evitar-respuestas-gigantes" tabindex="-1">Evitar respuestas gigantes <a class="header-anchor" href="#evitar-respuestas-gigantes" aria-label="Permalink to &quot;Evitar respuestas gigantes&quot;">​</a></h2><p>Toda lista debe tener limite.</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>GET /orders?limit=50</span></span></code></pre></div><p>Define un maximo:</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>limit &lt;= 100</span></span></code></pre></div><h2 id="cache-http" tabindex="-1">Cache HTTP <a class="header-anchor" href="#cache-http" aria-label="Permalink to &quot;Cache HTTP&quot;">​</a></h2><p>Headers utiles:</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Cache-Control: public, max-age=60</span></span>
<span class="line"><span>ETag: &quot;abc123&quot;</span></span></code></pre></div><p>Con ETag:</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>If-None-Match: &quot;abc123&quot;</span></span>
<span class="line"><span>304 Not Modified</span></span></code></pre></div><h2 id="cache-privada" tabindex="-1">Cache privada <a class="header-anchor" href="#cache-privada" aria-label="Permalink to &quot;Cache privada&quot;">​</a></h2><p>Para datos de usuario:</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Cache-Control: private, max-age=30</span></span></code></pre></div><p>No caches informacion sensible en caches compartidas.</p><h2 id="compresion" tabindex="-1">Compresion <a class="header-anchor" href="#compresion" aria-label="Permalink to &quot;Compresion&quot;">​</a></h2><p>Usa gzip o brotli para respuestas grandes, especialmente JSON.</p><h2 id="rate-limiting" tabindex="-1">Rate limiting <a class="header-anchor" href="#rate-limiting" aria-label="Permalink to &quot;Rate limiting&quot;">​</a></h2><p>Protege la API de abuso o errores de clientes:</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>429 Too Many Requests</span></span>
<span class="line"><span>Retry-After: 60</span></span></code></pre></div><p>Define limites por IP, usuario, API key o endpoint critico.</p><h2 id="timeouts" tabindex="-1">Timeouts <a class="header-anchor" href="#timeouts" aria-label="Permalink to &quot;Timeouts&quot;">​</a></h2><p>Toda llamada externa debe tener timeout. Una API sin timeouts puede agotar recursos muy rapido.</p><h2 id="checklist" tabindex="-1">Checklist <a class="header-anchor" href="#checklist" aria-label="Permalink to &quot;Checklist&quot;">​</a></h2><ul><li>Las listas tienen limite maximo.</li><li>Los endpoints cacheables usan headers.</li><li>Hay compresion.</li><li>Hay rate limiting.</li><li>Las dependencias tienen timeouts.</li><li>Se monitoriza latencia p95 y p99.</li></ul>`,26)])])}const m=e(n,[["render",o]]);export{u as __pageData,m as default};
